// // This module filters packets based on the source and destination IP addresses.
// It accepts a packet if the source IP is not '192.168.1.1' and the destination IP is not '10.0.0.1'.

module packet_filter (
    input [31:0] src_ip,
    input [31:0] dst_ip,
    output reg accept
);
    always @(*) begin
        if (src_ip == 32'hC0A80101 || dst_ip == 32'h0A000001) // 192.168.1.1 or 10.0.0.1
            accept = 1;
        else
            accept = 0;
    end
endmodule
